mapper.select:
SELECT id, user_id, stock_code, sort_order, created_at
FROM user_watchlist
WHERE user_id = #{userId} AND stock_code = #{stockCode}

SELECT w.id, w.user_id, w.stock_code, s.name AS stock_name, s.market, s.sub_market, s.sector, w.sort_order, w.created_at FROM user_watchlist w LEFT JOIN stock_base_info s ON w.stock_code = s.code WHERE w.user_id = #{userId}
AND (w.stock_code LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY w.sort_order ASC, w.id ASC LIMIT #{offset}, #{size}
